// Function to find union of two arrays
vector<int> FindUnion(int arr1[], int arr2[], int n, int m) {
    set<int> s;
    for (int i = 0; i < n; i++)
        s.insert(arr1[i]);
    for (int i = 0; i < m; i++)
        s.insert(arr2[i]);
    vector<int> v(s.begin(), s.end());
    sort(v.begin(), v.end());
    return v;
}

