code.Java:
import java.util.*;

// Define the Solution class
public class Solution {
    // Function to find union of two arrays
    public static List<Integer> FindUnion(int[] arr1, int[] arr2, int n, int m) {
        Set<Integer> s = new HashSet<>();
        for (int i = 0; i < n; i++)
            s.add(arr1[i]);
        for (int i = 0; i < m; i++)
            s.add(arr2[i]);
        List<Integer> v = new ArrayList<>(s);
        Collections.sort(v);
        return v;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int m = sc.nextInt();
        int[] arr1 = new int[n];
        int[] arr2 = new int[m];
        for (int i = 0; i < n; i++)
            arr1[i] = sc.nextInt();
        for (int i = 0; i < m; i++)
            arr2[i] = sc.nextInt();
        List<Integer> Union = FindUnion(arr1, arr2, n, m);
        for (int val : Union)
            System.out.print(val + " ");
    }
}

